import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. PRESTİJ VE KURUMSAL AYARLAR ---st.set_page_config(page_title="Focus AI | Professional Coach", layout="wide", initial_sidebar_state="expanded")# --- 2. STRATEJİK MÜFREDAT VERİTABANI (ÖSYM 2021-2025) ---MÜFREDAT_DATA = {    "TYT Matematik": {"Problemler": 12, "Sayılar": 3, "Geometri": 10, "Mantık/Kümeler": 2, "Fonksiyonlar": 1},    "AYT Matematik": {"Türev": 4, "İntegral": 4, "Trigonometri": 4, "Logaritma": 2, "Limit": 2, "Diziler": 1},    "TYT Türkçe": {"Paragraf": 26, "Dil Bilgisi": 7, "Anlam Bilgisi": 7},    "AYT Edebiyat": {"Divan": 5, "Cumhuriyet": 4, "Şiir Bilgisi": 3, "Edebi Sanatlar": 2},    "Sayısal Fen (AYT)": {"Sistemler": 4, "Modern Fizik": 2, "Organik Kimya": 3, "Elektrik": 3},    "Eşit Ağırlık Sosyal": {"Tarih-1": 10, "Coğrafya-1": 6, "Felsefe Grubu": 12}}# --- 3. MERKEZİ HAFIZA ---for key in ['ogrenciler', 'program', 'koc_notlari', 'denemeler']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Hedef Bölüm", "Veli Tel", "Koçluk Segmenti"])        elif key == 'program':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Soru Yükü", "Durum", "Tarih"])        elif key == 'koc_notlari':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Not", "Kritiklik"])        else:            st.session_state[key] = pd.DataFrame()# --- 4. YÖNETİM PANELİ (SIDEBAR) ---st.sidebar.title("🎯 Focus AI Coach")st.sidebar.markdown(f"**Tarih:** {datetime.now().strftime('%d.%m.%Y')}")role = st.sidebar.selectbox("Erişim Seviyesi:", ["👨‍🏫 KOÇLUK MERKEZİ", "🎓 ÖĞRENCİ GELİŞİM"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Öğrenci Kaydedilmedi"]# ==========================================# 👨‍🏫 MODÜL 1: KOÇLUK MERKEZİ (PRO)# ==========================================if role == "👨‍🏫 KOÇLUK MERKEZİ":    st.title("🏛️ Focus AI: Koçluk ve Mentorluk Operasyonu")        # Üst Metrikler (Global Durum)    m1, m2, m3, m4 = st.columns(4)    m1.metric("Aktif Danışan", len(st.session_state.ogrenciler))    m2.metric("Haftalık Görev Tamamlama", f"%{72}", "🚀 5%")    m3.metric("Kritik Bildirim", "3 Veli", delta_color="inverse")    m4.metric("Sistem Puanı", "9.2/10")    tabs = st.tabs(["💎 Mentorluk & Analiz", "📝 Müfredat Planlama", "👤 Danışan Kaydı", "📩 Veli Bildirimi"])    # --- TAB 1: MENTORLUK & ANALİZ ---    with tabs[0]:        st.subheader("🎯 Bireysel Gelişim Analizi")        sel_o = st.selectbox("Danışan Seçin:", ogrenci_listesi)                col_a1, col_a2 = st.columns([2, 1])        with col_a1:            # Radar Grafik (Koçluk Versiyonu)            categories = ['Akademik Net', 'Odaklanma Süresi', 'Soru Çözüm Hızı', 'Psikolojik Dayanıklılık', 'Düzenli Takip']            fig = go.Figure(data=go.Scatterpolar(r=[80, 70, 90, 65, 85], theta=categories, fill='toself', marker=dict(color='#1f77b4')))            fig.update_layout(polar=dict(radialaxis=dict(visible=True, range=[0, 100])), title=f"{sel_o} - Çok Yönlü Yetkinlik Radarı")            st.plotly_chart(fig, use_container_width=True)        with col_a2:            st.write("### 📝 Koçun Değerlendirme Notları")            k_not = st.text_area("Bugünkü görüşme notu...")            k_crit = st.select_slider("Kritiklik Seviyesi", options=["Düşük", "Normal", "Kritik"])            if st.button("Notu Arşive Ekle"):                st.toast("Görüşme notu başarıyla kaydedildi.")                        st.info("💡 **Koç Tavsiyesi:** Öğrencinin 'Psikolojik Dayanıklılık' puanı düşük. Bu hafta deneme sonuçları yerine 'süreç takibi' üzerine motivasyon görüşmesi yapılmalı.")    # --- TAB 2: MÜFREDAT PLANLAMA ---    with tabs[1]:        st.subheader("🛠️ Stratejik Yol Haritası Oluşturma")        with st.form("pro_odev"):            c1, c2, c3 = st.columns(3)            o_odev = c1.selectbox("Öğrenci", ogrenci_listesi)            d_odev = c2.selectbox("Ders", list(MÜFREDAT_DATA.keys()))            k_odev = st.multiselect("Hedef Konular", list(MÜFREDAT_DATA[d_odev].keys()))            kaynak = c3.text_input("Kaynak / Materyal")            if st.form_submit_button("Yol Haritasına Ekle"):                for k in k_odev:                    s_y = MÜFREDAT_DATA[d_odev][k]                    yeni = pd.DataFrame([[o_odev, d_odev, k, s_y, "Bekliyor", datetime.now()]], columns=st.session_state.program.columns)                    st.session_state.program = pd.concat([st.session_state.program, yeni], ignore_index=True)                st.success("Haftalık plan başarıyla güncellendi.")    # --- TAB 3: DANIŞAN KAYDI ---    with tabs[2]:        st.subheader("👤 Yeni Danışan Kaydı")        with st.form("pro_kayit"):            c_a, c_h, c_t = st.columns(3)            n_ad = c_a.text_input("Ad Soyad")            n_hed = c_h.text_input("Hedef Bölüm (Örn: İTÜ Bilgisayar)")            n_tel = c_t.text_input("Veli WhatsApp (905...)")            n_seg = st.select_slider("Koçluk Yoğunluğu", options=["Standart", "VIP", "Elite"])            if st.form_submit_button("Sisteme Dahil Et"):                yeni_og = pd.DataFrame([[n_ad, n_hed, n_tel, n_seg]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_og], ignore_index=True)                st.rerun()        st.dataframe(st.session_state.ogrenciler, use_container_width=True)    # --- TAB 4: VELİ BİLDİRİMİ ---    with tabs[3]:        st.subheader("📩 Veli WhatsApp İletişim Hattı")        if not st.session_state.ogrenciler.empty:            v_sel = st.selectbox("Veli Seç:", ogrenci_listesi)            v_data = st.session_state.ogrenciler[st.session_state.ogrenciler["Ad Soyad"] == v_sel].iloc[0]            v_msg = f"Sayın Velimiz, bugün {v_sel} ile yaptığımız koçluk görüşmesinde akademik ilerlemesi %85 olarak saptanmıştır. Haftalık hedeflerine odaklanması devam etmektedir."            st.link_button(f"🟢 {v_data['Veli Tel']} Numarasına Rapor Gönder", f"https://wa.me/{v_data['Veli Tel']}?text={v_msg.replace(' ', '%20')}")# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ GELİŞİM (DANIŞAN)# ==========================================else:    st.title("🎓 Focus AI: Kişisel Gelişim Portalı")    st.markdown(f"### Merhaba! Bugün senin için **stratejik** bir gün. 🚀")        # Gelişim Çubuğu    st.write("Haftalık Hedef Tamamlama")    st.progress(0.68)        col_o1, col_o2 = st.columns([2, 1])        with col_o1:        st.subheader("📅 Aktif Görevlerin")        if not st.session_state.program.empty:            for i, r in st.session_state.program.iterrows():                if r["Durum"] == "Bekliyor":                    with st.expander(f"📌 {r['Ders']} | {r['Konu']}"):                        st.write(f"**Önem Derecesi:** {r['Soru Yükü']} Soru (Sınav Ağırlığı)")                        if st.button("Görevi Tamamladım", key=i):                            st.session_state.program.at[i, "Durum"] = "Tamamlandı"                            st.rerun()        else:            st.success("Koçun henüz yeni görev atamamış. Dinlenebilirsin!")    with col_o2:        st.subheader("🏆 Başarı Puanın")        st.metric("Focus Point", "1,250", "+150")        st.write("---")        st.subheader("📺 Koçun Önerdiği Videolar")        st.video("https://www.youtube.com/watch?v=dQw4w9WgXcQ")